/**
 * @summary Admin - get all businesses including unverified
 */
export const getGetAdminBusinessesUrl = (params?: GetAdminBusinessesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/businesses?${stringifiedParams}`
    : `/api/admin/businesses`;
};

export const getAdminBusinesses = async (
  params?: GetAdminBusinessesParams,
  options?: RequestInit,
): Promise<Business[]> => {
  return customFetch<Business[]>(getGetAdminBusinessesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetAdminBusinessesQueryKey = (
  params?: GetAdminBusinessesParams,
) => {
  return [`/api/admin/businesses`, ...(params ? [params] : [])] as const;
};

export const getGetAdminBusinessesQueryOptions = <
  TData = Awaited<ReturnType<typeof getAdminBusinesses>>,
  TError = ErrorType<unknown>,
>(
  params?: GetAdminBusinessesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAdminBusinesses>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAdminBusinessesQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getAdminBusinesses>>
  > = ({ signal }) => getAdminBusinesses(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAdminBusinesses>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAdminBusinessesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAdminBusinesses>>
>;
export type GetAdminBusinessesQueryError = ErrorType<unknown>;

/**
 * @summary Admin - get all businesses including unverified
 */

export function useGetAdminBusinesses<
  TData = Awaited<ReturnType<typeof getAdminBusinesses>>,
  TError = ErrorType<unknown>,
>(
  params?: GetAdminBusinessesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAdminBusinesses>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAdminBusinessesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
